package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsNull() throws Exception {
        // Use DEFAULT which has escapeCharacter null
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsSet() throws Exception {
        // Use withEscape to set escape character
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');
        assertTrue(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSet_withEscapeCharacterNullExplicit() throws Exception {
        // Explicitly set escapeCharacter to null with withEscape(Character)
        CSVFormat format = CSVFormat.DEFAULT.withEscape((Character) null);
        assertFalse(format.isEscapeCharacterSet());
    }
}
